from flask import Flask, redirect, request, session, url_for
import requests
import os
import time

app = Flask(__name__)
app.secret_key = os.urandom(24)

# OIDC Configuration
OIDC_ISSUER = 'https://your-oidc-provider.com'
OIDC_CLIENT_ID = 'your-client-id'
OIDC_CLIENT_SECRET = 'your-client-secret'
OIDC_REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/')
def index():
    nonce = str(time.time())
    session['nonce'] = nonce
    auth_url = f"{OIDC_ISSUER}/authorize?response_type=code&client_id={OIDC_CLIENT_ID}&redirect_uri={OIDC_REDIRECT_URI}&scope=openid%20profile&nonce={nonce}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    nonce = session.pop('nonce', None)
    
    if not nonce:
        return "Invalid state", 400

    token_url = f"{OIDC_ISSUER}/token"
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_REDIRECT_URI,
        'client_id': OIDC_CLIENT_ID,
        'client_secret': OIDC_CLIENT_SECRET
    }
    
    response = requests.post(token_url, data=data)
    tokens = response.json()
    
    id_token = tokens.get('id_token')
    if not id_token:
        return "ID token missing", 400

    # Decode and verify the id_token (this is a simplified example)
    # In production, use libraries like PyJWT to decode and verify
    user_claims = {
        'sub': 'user-subject',
        'name': 'User Name',
        'email': 'user@example.com'
    }
    
    session['user'] = user_claims
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)